let SUBMIT_BTN_ORIGINAL_HTML=null;function captureSubmitBtnOriginalHTML(){if(SUBMIT_BTN_ORIGINAL_HTML!==null)return;const btn=document.getElementById("submit-btn");if(btn)SUBMIT_BTN_ORIGINAL_HTML=btn.innerHTML;}
function isSubmitTargetStillCurrent(taskId){if(!taskId)return!window.activeTaskId;return window.activeTaskId===taskId;}
