async function testNotification(){try{await notificationManager.sendNotification(t("status.testNotifyTitle"),t("status.testNotifyBody"),{tag:"test-notification",requireInteraction:false,},);showStatus(t("status.testNotifySent"),"success");}catch(error){console.error("Test notification failed:",error);showStatus(t("status.testNotifyFailed"),"error");}}
function handleGlobalKeydown(event){const isMac=detectPlatform()==="mac";const ctrlOrCmd=isMac?event.metaKey:event.ctrlKey;const altOrOption=isMac?event.altKey:event.altKey;if(ctrlOrCmd&&event.key==="Enter"){event.preventDefault();submitFeedback();}else if(altOrOption&&event.key==="c"){event.preventDefault();insertCodeFromClipboard();}else if(ctrlOrCmd&&event.key==="v"){console.debug(`Shortcut: ${isMac ? "Cmd" : "Ctrl"}+V paste`);}else if(ctrlOrCmd&&event.key==="u"){event.preventDefault();const uploadBtn=document.getElementById("upload-image-btn");if(uploadBtn&&typeof uploadBtn.click==="function"){uploadBtn.click();console.debug(`Shortcut: ${isMac ? "Cmd" : "Ctrl"}+U upload image`);}else{console.debug("Shortcut upload skipped: upload button unavailable");}}else if(event.key==="Delete"&&selectedImages.length>0){event.preventDefault();clearAllImages();console.debug("Shortcut: Delete clear all images");}else if(ctrlOrCmd&&event.shiftKey&&event.key==="N"){event.preventDefault();testNotification();console.debug(`Shortcut: ${isMac ? "Cmd" : "Ctrl"}+Shift+N test notification`,);}}
